import React, { useEffect } from 'react';
import { NetInfo } from '@react-native-community/netinfo';
import AsyncStorage from '@react-native-async-storage/async-storage';
import { useDispatch, useSelector } from 'react-redux';

const DebuggingModule = () => {
  const dispatch = useDispatch();
  const authState = useSelector(state => state.auth);
  const userState = useSelector(state => state.user);

  useEffect(() => {
    // Log network requests
    const handleNetworkChange = (state) => {
      console.log('Network status changed:', state.isConnected, 'Type:', state.type);
    };

    NetInfo.addEventListener(handleNetworkChange);

    return () => {
      NetInfo.removeEventListener(handleNetworkChange);
    };
  }, []);

  useEffect(() => {
    // Log AsyncStorage operations
    const logAsyncStorage = async (key, value) => {
      console.debug('AsyncStorage operation:', key, 'Value:', value);
    };

    const originalSetItem = AsyncStorage.setItem;
    AsyncStorage.setItem = async (...args) => {
      await logAsyncStorage(args[0], args[1]);
      return originalSetItem.apply(AsyncStorage, args);
    };

    const originalRemoveItem = AsyncStorage.removeItem;
    AsyncStorage.removeItem = async (key) => {
      await logAsyncStorage(key, 'Removed');
      return originalRemoveItem.call(AsyncStorage, key);
    };

    return () => {
      AsyncStorage.setItem = originalSetItem;
      AsyncStorage.removeItem = originalRemoveItem;
    };
  }, []);

  useEffect(() => {
    // Log user actions
    const logUserAction = (action) => {
      console.log('User action:', action.type, 'Payload:', action.payload);
    };

    const dispatchWithLogging = (...args) => {
      logUserAction(args[0]);
      return dispatch(...args);
    };

    dispatchWithLogging.bind(dispatch);

    return () => {
      dispatchWithLogging.unbind();
    };
  }, [dispatch]);

  useEffect(() => {
    // Log state changes
    console.debug('State changed - Auth State:', authState, 'User State:', userState);
  }, [authState, userState]);

  useEffect(() => {
    // Log authentication tokens and user data
    if (authState.token) {
      console.log('Authentication Token:', authState.token);
    }
    if (userState.data) {
      console.debug('User Data:', userState.data);
    }
  }, [authState, userState]);

  return null;
};

export default DebuggingModule;